VALUES
  ('social-worker-moex-06620', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'essay', '近年來社會企業（Social Enterprise）議題的討論頗為熱烈，請說明何謂社會企業？
可分成那幾種類型？請舉一個你所了解的社會企業的例子，並說明這個例子所面臨
的管理問題有那些？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06621', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作者若表現良好，可能晉升為督導或主管，然而在科層層級依照能力往上升遷過程中，若晉升到 某個位置，是不適合自己或自己無法勝任者，此一現象稱之為：', '["倫理困境", "帕金森定律", "彼得原理", "墨菲法則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06622', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作中，系統理論一直具有其重要性地位，但在系統取向中，管理者的主要角色在於觀察其所管理 的次級系統，如何在不同的互動介面，與較大的或整個系統，及外在世界產生關聯，此一概念稱之為：', '["科學管理（scientific management）", "非正式管理（informal management）", "科層體制（bureaucracy）", "界限管理（boundary management）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06623', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一非營利組織特別強調社會和人際互動關係，較不重視工作環境、工作條件與獎勵制度，是受何種效 應理論的影響，下列何者正確？', '["衣尾效應（coattail effect）", "月暈效應（halo effect）", "蝴蝶效應（butterfly effect）", "霍桑效應（Hawthorne effect）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06624', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理學者彼得聖吉（Peter M. Senge）倡導學習型組織，其主張組織成員要透過五種修練來觀察並掌握環 境變化以開創新局，下列何者不是其所提出的五項要素？', '["合法性權威（legal authority）", "自我超越（personal mastery）", "改進心智模式（improve mental models）", "建立共同願景（building shared vision）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06625', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會學家Weber提出科層管理觀點，Stewart進一步將科層組織的運作方式歸納為那四個主要特性，下列 何者正確？', '["非個人化（impersonality）", "去法制化（de-regulation）", "去授權化（de-authorization）", "反規格化（anti-specifications）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06626', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於社會工作管理來說，新公共管理的運作模式，其主要特性可歸納下列幾項，下列何者最正確？', '["明確指出社會工作績效的標準和測量，且提供誘因與服務過程連結的契約網絡", "強調社會工作服務之買方與賣方合作之準契約和準市場的服務供給模式", "重視社會工作之資源配置的紀律和節約", "降低政治決策對社會工作服務管理的間接干預"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06627', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當社會工作專業遭遇到新管理主義的挑戰時，會有什麼樣的挑戰，下列何者最正確？', '["有去專業化（de-professionalization）的現實性", "有去法制化（de-regulation）的可能性", "有去機構化（de-institutionalization）的企圖性", "有反專業重構（anti-professional reconstruction）的必要性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06628', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關行銷組合的概念，傳統上以1960年麥卡錫（McCarthy）所提出的4P組合為主，學者Booms與Bitner 則延伸該概念而擴大為7P行銷組合，下列何者為4P以外的7P概念？', '["產品（Product）", "過程（Process）", "促銷（Promotion）", "調查（Probing）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06629', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理的過程包括數項活動，每項活動即是代表著管理的基本功能，下列何者是真正管理過程之基本功能？', '["規劃（planning）", "實作（doing）", "檢查（checking）", "行動（acting）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
